create table auth_account (enabled boolean not null, created_at timestamp(6) with time zone not null, updated_at timestamp(6) with time zone not null, id uuid not null, user_id uuid not null, password_hash varchar(255), provider varchar(255) not null check ((provider in ('LOCAL','GOOGLE'))), provider_user_id varchar(255), primary key (id), unique (provider, provider_user_id), unique (user_id, provider));
create table budgets (amount numeric(38,2), start_date date, threshold_critical integer, threshold_warning integer, created_at timestamp(6) with time zone not null, updated_at timestamp(6) with time zone not null, category_id uuid, id uuid not null, user_id uuid not null, wallet_id uuid not null, last_alert_status varchar(255) check ((last_alert_status in ('OK','WARNING','CRITICAL','EXCEEDED'))), period varchar(255) check ((period in ('DAILY','WEEKLY','MONTHLY'))), scope varchar(255) check ((scope in ('WALLET','CATEGORY'))), primary key (id));
create table categories (system_defined boolean not null, created_at timestamp(6) with time zone not null, id uuid not null, color varchar(255), icon varchar(255), name varchar(255) not null, type varchar(255) check ((type in ('INCOME','EXPENSE','TRANSFER'))), primary key (id));
create table expenses (amount numeric(15,2) not null, auto_generated boolean not null, categorization_changes integer not null, confidence_score float(53), date date not null, edit_count integer not null, is_default boolean not null, recurring boolean not null, reimbursable boolean not null, tax_deductible boolean not null, created_at timestamp(6) with time zone not null, category_id uuid, id uuid not null, user_id uuid not null, wallet_id uuid not null, description varchar(150), recurrence_pattern varchar(255), source varchar(255) not null, title varchar(255) not null, primary key (id));
create table idempotency_keys (status_code integer not null, created_at timestamp(6) with time zone not null, expires_at timestamp(6) with time zone not null, id uuid not null, user_id uuid not null, endpoint varchar(255) not null, idempotency_key varchar(255) not null, request_hash varchar(255) not null, response_body TEXT not null, primary key (id), unique (idempotency_key, user_id, endpoint));
create table incomes (amount numeric(15,2) not null, auto_generated boolean not null, categorization_changes integer not null, confidence_score float(53), date date not null, edit_count integer not null, recurring boolean, taxable boolean, created_at timestamp(6) with time zone not null, category_id uuid, id uuid not null, user_id uuid not null, wallet_id uuid not null, description varchar(150), recurrence_pattern varchar(255), source varchar(255) not null, title varchar(255) not null, primary key (id));
create table merchant_patterns (priority integer not null, category_id uuid not null, id uuid not null, pattern varchar(255) not null, primary key (id));
create table notifications (read boolean, created_at timestamp(6) with time zone, id uuid not null, user_id uuid, message varchar(255), title varchar(255), type varchar(255) check ((type in ('BUDGET_SUCCESS','BUDGET_WARNING','BUDGET_CRITICAL','BUDGET_EXCEEDED','GOAL_REACHED','NEW_CONTRIBUTOR','ACCOUNT_LOCKED'))), primary key (id));
create table payments (amount numeric(10,2) not null, created_at timestamp(6) with time zone not null, id uuid not null, subscription_id uuid not null, user_id uuid not null, currency varchar(255) not null, external_transaction_id varchar(255) not null unique, provider varchar(255) not null, status varchar(255) not null check ((status in ('PENDING','PAID','FAILED','REFUNDED'))), primary key (id));
create table plans (active boolean not null, can_create_shared_wallets boolean not null, dashboard_customization boolean not null, export_enabled boolean not null, max_budgets integer not null, max_recurring_transactions integer not null, max_shared_wallets integer, max_wallet_members integer, max_wallets integer not null, price numeric(10,2) not null, created_at timestamp(6) with time zone not null, updated_at timestamp(6) with time zone not null, id uuid not null, code varchar(50) not null unique, name varchar(100) not null, billing_period varchar(255) not null check ((billing_period in ('MONTHLY','YEARLY'))), primary key (id));
create table recurring_transactions (active boolean not null, amount numeric(15,2) not null, end_date date, interval_value integer not null, next_execution_date date not null, start_date date not null, category_id uuid, id uuid not null, user_id uuid not null, wallet_id uuid not null, description varchar(150), frequency varchar(255) not null check ((frequency in ('DAILY','WEEKLY','MONTHLY'))), title varchar(255) not null, type varchar(255) not null check ((type in ('EXPENSE','INCOME'))), primary key (id));
create table subscriptions (auto_renew boolean not null, current_price numeric(10,2) not null, canceled_at timestamp(6) with time zone, created_at timestamp(6) with time zone not null, ends_at timestamp(6) with time zone not null, next_billing_at timestamp(6) with time zone, starts_at timestamp(6) with time zone not null, updated_at timestamp(6) with time zone not null, id uuid not null, plan_id uuid not null, user_id uuid not null, status varchar(255) not null check ((status in ('ACTIVE','EXPIRED','CANCELED','PAST_DUE'))), primary key (id));
create table transfer (amount numeric(38,2), created_at timestamp(6) with time zone not null, from_wallet_id uuid not null, id uuid not null, to_wallet_id uuid not null, user_id uuid not null, description varchar(255), status varchar(255) check ((status in ('COMPLETED'))), primary key (id));
create table user_roles (user_id uuid not null, role varchar(255), unique (user_id, role));
create table users (email_verified boolean not null, created_at timestamp(6) with time zone not null, updated_at timestamp(6) with time zone not null, id uuid not null, cognito_sub varchar(255) unique, email varchar(255) not null unique, status varchar(255) not null check ((status in ('ACTIVE','SUSPENDED','DELETED'))), primary key (id));
create table wallet_users (created_at timestamp(6) with time zone not null, id uuid not null, user_id uuid not null, wallet_id uuid not null, role varchar(255) check ((role in ('OWNER','MEMBER'))), primary key (id), unique (wallet_id, user_id));
create table wallets (balance numeric(38,2) not null, initial_value numeric(38,2) not null, created_at timestamp(6) with time zone not null, updated_at timestamp(6) with time zone not null, version bigint not null, id uuid not null, currency varchar(255) not null check ((currency in ('USD','EUR','MXN'))), description varchar(255) not null, name varchar(255) not null, primary key (id));
create index idx_subscription_user on subscriptions (user_id);
create index idx_subscription_status on subscriptions (status);
create index idx_subscription_next_billing on subscriptions (next_billing_at);
create index idx_wallet_user on wallet_users (wallet_id, user_id);
